import{_ as e,o as n,c as r,ag as o}from"./chunks/framework.DXGyWiRo.js";const h=JSON.parse('{"title":"IDE Settings","description":"","frontmatter":{},"headers":[],"relativePath":"configuration/ide-settings.md","filePath":"configuration/ide-settings.md"}'),a={name:"configuration/ide-settings.md"};function i(s,t,d,l,g,p){return n(),r("div",null,[...t[0]||(t[0]=[o('<h1 id="ide-settings" tabindex="-1">IDE Settings <a class="header-anchor" href="#ide-settings" aria-label="Permalink to &quot;IDE Settings&quot;">​</a></h1><p>EasyApi settings can be accessed via <strong>Preferences(Settings)</strong> &gt; <strong>Other Settings</strong> &gt; <strong>EasyApi</strong>.</p><p>The settings dialog contains the following tabs:</p><h2 id="general" tabindex="-1">General <a class="header-anchor" href="#general" aria-label="Permalink to &quot;General&quot;">​</a></h2><p>General plugin settings:</p><table tabindex="0"><thead><tr><th>Setting</th><th>Description</th></tr></thead><tbody><tr><td><strong>Enable built-in configuration</strong></td><td>Load built-in extension configs for common frameworks</td></tr><tr><td><strong>Build example in Postman export</strong></td><td>Generate example responses in Postman collections</td></tr><tr><td><strong>Auto-merge scripts in Postman export</strong></td><td>Automatically merge pre-request and test scripts</td></tr></tbody></table><h2 id="postman" tabindex="-1">Postman <a class="header-anchor" href="#postman" aria-label="Permalink to &quot;Postman&quot;">​</a></h2><p>Postman-specific settings:</p><table tabindex="0"><thead><tr><th>Setting</th><th>Description</th></tr></thead><tbody><tr><td><strong>Postman Token</strong></td><td>Your Postman API token for direct upload</td></tr><tr><td><strong>Export Mode</strong></td><td>How to export (update existing / create new)</td></tr><tr><td><strong>Collection ID</strong></td><td>Target collection ID for export</td></tr><tr><td><strong>Workspace ID</strong></td><td>Target workspace ID</td></tr></tbody></table><h2 id="http" tabindex="-1">HTTP <a class="header-anchor" href="#http" aria-label="Permalink to &quot;HTTP&quot;">​</a></h2><p>Configure the built-in HTTP client:</p><table tabindex="0"><thead><tr><th>Setting</th><th>Description</th></tr></thead><tbody><tr><td><strong>HTTP Client Type</strong></td><td>Select HTTP client implementation</td></tr><tr><td><strong>Connect Timeout</strong></td><td>Connection timeout in milliseconds</td></tr><tr><td><strong>Read Timeout</strong></td><td>Read timeout in milliseconds</td></tr><tr><td><strong>Proxy</strong></td><td>HTTP proxy settings</td></tr></tbody></table><h2 id="intelligent" tabindex="-1">Intelligent <a class="header-anchor" href="#intelligent" aria-label="Permalink to &quot;Intelligent&quot;">​</a></h2><p>Intelligent scanning and detection settings:</p><table tabindex="0"><thead><tr><th>Setting</th><th>Description</th></tr></thead><tbody><tr><td><strong>Auto Scan Enabled</strong></td><td>Automatically scan for API endpoints</td></tr><tr><td><strong>Concurrent Scan Enabled</strong></td><td>Use concurrent scanning for better performance</td></tr></tbody></table><h2 id="extensions" tabindex="-1">Extensions <a class="header-anchor" href="#extensions" aria-label="Permalink to &quot;Extensions&quot;">​</a></h2><p>Manage extension configurations that provide framework-specific rules. Extensions can be enabled or disabled individually.</p><p>Available extensions include:</p><ul><li>Spring Web support</li><li>Spring Boot support</li><li>Spring WebFlux support</li><li>Feign support</li><li>JAX-RS support</li><li>javax.validation support</li><li>Jakarta validation support</li><li>Jackson support</li><li>Gson support</li><li>Swagger 2 support</li><li>Swagger 3 (OpenAPI) support</li><li>Spring properties support</li></ul><h2 id="remote" tabindex="-1">Remote <a class="header-anchor" href="#remote" aria-label="Permalink to &quot;Remote&quot;">​</a></h2><p>Add remote configuration file URLs. Remote configs are loaded after local configs and can override local settings.</p><p>See <a href="/configuration/remote-config.html">Remote Config</a> for details.</p><h2 id="built-in" tabindex="-1">Built-in <a class="header-anchor" href="#built-in" aria-label="Permalink to &quot;Built-in&quot;">​</a></h2><p>View the built-in configuration rules that ship with EasyApi.</p><h2 id="other" tabindex="-1">Other <a class="header-anchor" href="#other" aria-label="Permalink to &quot;Other&quot;">​</a></h2><p>Additional settings:</p><table tabindex="0"><thead><tr><th>Setting</th><th>Description</th></tr></thead><tbody><tr><td><strong>Markdown Format</strong></td><td>Output format for Markdown export</td></tr><tr><td><strong>Log Level</strong></td><td>Plugin logging verbosity</td></tr></tbody></table><h2 id="grpc" tabindex="-1">gRPC <a class="header-anchor" href="#grpc" aria-label="Permalink to &quot;gRPC&quot;">​</a></h2><p>Configure gRPC support:</p><table tabindex="0"><thead><tr><th>Setting</th><th>Description</th></tr></thead><tbody><tr><td><strong>Enable gRPC support</strong></td><td>Recognize gRPC service classes</td></tr><tr><td><strong>Enable gRPC call</strong></td><td>Allow calling gRPC endpoints from the IDE</td></tr><tr><td><strong>Runtime Artifacts</strong></td><td>gRPC runtime JARs for dynamic invocation</td></tr><tr><td><strong>Auto Detect</strong></td><td>Automatically detect gRPC artifacts in project</td></tr></tbody></table><p>See <a href="/frameworks/grpc.html">gRPC</a> for more details.</p>',31)])])}const u=e(a,[["render",i]]);export{h as __pageData,u as default};
